import React, { useEffect, useState, useRef } from "react";
import { Link } from "react-router-dom";

// components
import Navbar from "components/Navbars/AuthNavbar.js";
import Footer from "components/Footers/Footer.js";

export default function Landing() {
  const texts = [
    "Hello", "Bonjour", "Ciao", "Hola", "こんにちは", "你好", "안녕하세요", "नमस्ते", "مرحبا"
  ];

  const [index, setIndex] = useState(0);
  const [selectedImage, setSelectedImage] = useState(null);
  const [hoveredId, setHoveredId] = useState(null);
  const [navbarHeight, setNavbarHeight] = useState(0);
  const [isAnyHovered, setIsAnyHovered] = useState(false);

  const timeoutRef = useRef(null);
  const containerRef = useRef(null);

  useEffect(() => {
    const interval = setInterval(() => {
      if (!isAnyHovered) {
        setIndex((prev) => (prev + 1) % texts.length);
      }
    }, 2000);
    return () => clearInterval(interval);
  }, [isAnyHovered]);

  useEffect(() => {
    const update = () => {
      const navbar = document.querySelector("nav");
      if (navbar) setNavbarHeight(navbar.offsetHeight);
    };
    update();
    window.addEventListener("resize", update);
    return () => window.removeEventListener("resize", update);
  }, []);

  const images = [
    {
      id: 1,
      position: "left",
      url: "https://media.licdn.com/dms/image/v2/D4D22AQFq6-imvZP4iA/feedshare-shrink_2048_1536/feedshare-shrink_2048_1536/0/1687664122353?e=2147483647&v=beta&t=bCaAAhhO43wxx2z9S93n-vThZFHOHJeiIo0A_xNv6n8",
      title: "رمز QR",
      icon: "📱",
      description: "طريقة ذكية لبدء الطلب بدون انتظار النادل",
      fullDescription: "يقوم الزبون بمسح رمز QR الموجود على الطاولة، ليتم فتح قائمة الطعام الرقمية مباشرة على هاتفه. يختار الأطباق المفضلة ويضيفها إلى السلة بكل سهولة، ثم يرسل الطلب مباشرة إلى المطبخ.",
      features: ["⚡ مسح سريع خلال ثانية", "📱 قائمة تفاعلية", "🚀 إرسال مباشر للمطبخ"],
      explainText: "📱 **مسح رمز QR** | عند مسح الرمز الموجود على الطاولة، يتم فتح قائمة الطعام الرقمية مباشرة على هاتفك. يمكنك تصفح جميع الأطباق مع صورها وأسعارها، إضافة ما ترغب إلى سلة الطلبات، ثم إرسال الطلب بنقرة واحدة إلى المطبخ. تجربة سريعة وسلسة بدون انتظار النادل! ✨"
    },
    {
      id: 2,
      position: "center",
      url: "https://png.pngtree.com/png-clipart/20190611/original/pngtree-restaurant-waiter-png-image_2875285.jpg",
      title: "العامل والطلبات",
      icon: "👨‍🍳",
      description: "إدارة فعالة وسريعة للطلبات",
      fullDescription: "يستقبل العامل الطلبات مباشرة على جهازه اللوحي، مع تفاصيل كل طلب: اسم الطبق، الكمية، الملاحظات الخاصة. يتم تحديد مكان الطاولة بدقة، ويظهر ثمن كل طلب بشكل فوري.",
      features: ["📍 تحديد موقع الطاولة", "💰 عرض الأسعار الفورية", "📝 ملاحظات للطاهي"],
      explainText: "👨‍🍳 **إدارة ذكية للطلبات** | يستقبل العامل جميع الطلبات فوراً على جهازه اللوحي مع تفاصيل دقيقة: رقم الطاولة، الأطباق المطلوبة، الكميات، والملاحظات الخاصة للطاهي. يمكنه متابعة حالة كل طلب وتحديثها لحظة بلحظة لضمان خدمة سريعة ودقيقة."
    },
    {
      id: 3,
      position: "right",
      url: "https://png.pngtree.com/thumb_back/fw800/background/20221004/pngtree-closeup-of-100dollar-bill-with-inflation-and-economy-concept-photo-image_48961572.jpg",
      title: "الفاتورة الذكية",
      icon: "💰",
      description: "حساب آلي دقيق للمجموع",
      fullDescription: "يقوم النظام تلقائياً بحساب إجمالي الطلبات مع الضريبة، ويظهر تفاصيل كل صنف وسعره. يمكن للزبون دفع الفاتورة إلكترونياً عبر التطبيق، أو طلب الفاتورة الورقية.",
      features: ["🧮 حساب المجموع مع الضريبة", "📊 تفاصيل كل صنف", "💳 دفع إلكتروني آمن"],
      explainText: "💰 **فاتورة دقيقة وسريعة** | النظام يحسب تلقائياً إجمالي الطلبات مع إضافة الضريبة، ويعرض تفاصيل كل صنف وسعره بوضوح. يمكن للزبون دفع الفاتورة إلكترونياً عبر التطبيق بطرق آمنة، أو طلب فاتورة ورقية من العامل. شفافية تامة وسرعة في الإنجاز!"
    }
  ];

  const handleMouseEnter = (id, position) => {
    if (timeoutRef.current) clearTimeout(timeoutRef.current);
    setHoveredId(id);
    setIsAnyHovered(true);

    const container = containerRef.current;
    if (!container) return;
    const items = container.children;

    if (position === "left") {
      items[0].style.flex = "0 1 50%";
      items[1].style.flex = "0 0 25%";
      items[2].style.flex = "0 0 25%";
    } else if (position === "center") {
      items[0].style.flex = "0 0 20%";
      items[1].style.flex = "0 1 60%";
      items[2].style.flex = "0 0 20%";
    } else {
      items[0].style.flex = "0 0 25%";
      items[1].style.flex = "0 0 25%";
      items[2].style.flex = "0 1 50%";
    }

    if (items[0]) items[0].style.zIndex = position === "left" ? "10" : "1";
    if (items[1]) items[1].style.zIndex = position === "center" ? "10" : "1";
    if (items[2]) items[2].style.zIndex = position === "right" ? "10" : "1";
  };

  const handleMouseLeave = () => {
    timeoutRef.current = setTimeout(() => {
      setHoveredId(null);
      setIsAnyHovered(false);
      const container = containerRef.current;
      if (!container) return;
      for (let item of container.children) {
        item.style.flex = "1";
        item.style.zIndex = "1";
      }
    }, 150);
  };

  useEffect(() => {
    return () => {
      if (timeoutRef.current) clearTimeout(timeoutRef.current);
    };
  }, []);

  const openModal = (image) => {
    setSelectedImage(image);
    document.body.style.overflow = "hidden";
  };

  const closeModal = () => {
    setSelectedImage(null);
    document.body.style.overflow = "auto";
  };

  return (
    <>
      <Navbar transparent />
      <main>
        <div 
          className="relative flex content-center items-center justify-center min-h-screen"
          style={{ paddingTop: `${navbarHeight}px` }}
        >
          {/* ✅ خلفية متدرجة من الأزرق إلى الأخضر */}
          <div className="absolute top-0 w-full h-full bg-gradient-to-r from-blue-900 via-green-800 to-green-900">
            <div className="absolute inset-0 opacity-20" style={{
              backgroundImage: `radial-gradient(circle at 2px 2px, #22c55e 1px, transparent 1px)`,
              backgroundSize: '40px 40px'
            }}></div>
          </div>

          {/* الصور الثلاث */}
          <div className="absolute top-0 w-full h-full z-10" style={{ paddingTop: `${navbarHeight}px` }}>
            <ul 
              ref={containerRef}
              className="w-full h-full flex m-0 p-0" 
              style={{ listStyle: "none" }}
            >
              {images.map((image, idx) => (
                <li
                  key={image.id}
                  className="relative overflow-hidden cursor-pointer"
                  style={{
                    flex: 1,
                    transition: "flex 0.4s cubic-bezier(0.25, 0.46, 0.45, 0.94)",
                    borderRight: idx < images.length - 1 ? "2px solid rgba(34, 197, 94, 0.3)" : "none",
                    willChange: "flex",
                  }}
                  onClick={() => openModal(image)}
                  onMouseEnter={() => handleMouseEnter(image.id, image.position)}
                  onMouseLeave={handleMouseLeave}
                >
                  {/* الصورة - تتحرك لأعلى اليمين وتتصغر */}
                  <img
                    src={image.url}
                    alt={image.title}
                    className="absolute transition-all duration-500"
                    style={{
                      top: hoveredId === image.id ? "20px" : "50%",
                      right: hoveredId === image.id ? "20px" : "auto",
                      left: hoveredId === image.id ? "auto" : "50%",
                      transform: hoveredId === image.id ? "translate(0, 0)" : "translate(-50%, -50%)",
                      width: hoveredId === image.id ? "80px" : "100%",
                      height: hoveredId === image.id ? "80px" : "100%",
                      objectFit: hoveredId === image.id ? "contain" : "cover",
                      borderRadius: hoveredId === image.id ? "12px" : "0",
                      boxShadow: hoveredId === image.id ? "0 0 20px rgba(34, 197, 94, 0.5)" : "none",
                      zIndex: hoveredId === image.id ? 20 : 1,
                    }}
                  />

                  {/* ✅ النص يظهر مباشرة على الخلفية الرئيسية - بدون طبقة خضراء إضافية */}
                  <div 
                    className="absolute inset-0 transition-all duration-500 flex items-center justify-center"
                    style={{
                      opacity: hoveredId === image.id ? 1 : 0,
                      visibility: hoveredId === image.id ? "visible" : "hidden",
                      transition: "all 0.5s ease",
                      background: "transparent", // ✅ بدون خلفية إضافية
                    }}
                  >
                    <div 
                      className="w-[90%] max-w-3xl text-center transition-all duration-500"
                      style={{
                        opacity: hoveredId === image.id ? 1 : 0,
                        transform: hoveredId === image.id ? "scale(1)" : "scale(0.9)",
                        transition: "all 0.5s cubic-bezier(0.34, 1.2, 0.64, 1)",
                      }}
                    >
                      <span className="text-6xl md:text-7xl drop-shadow-lg block mb-4">{image.icon}</span>
                      <h2 className="text-white text-3xl md:text-4xl lg:text-5xl font-bold mb-4" style={{
                        textShadow: "0 2px 15px rgba(0,0,0,0.5)",
                        background: "linear-gradient(135deg, #22c55e, #ffffff)",
                        WebkitBackgroundClip: "text",
                        WebkitTextFillColor: "transparent",
                        backgroundClip: "text"
                      }}>
                        {image.title}
                      </h2>
                      <p className="text-white text-base md:text-lg lg:text-xl leading-relaxed mb-6 px-4 drop-shadow-md" style={{
                        textShadow: "0 1px 5px rgba(0,0,0,0.3)"
                      }}>
                        {image.explainText}
                      </p>
                      <button 
                        onClick={(e) => {
                          e.stopPropagation();
                          openModal(image);
                        }}
                        className="inline-flex items-center gap-2 text-base md:text-lg bg-gradient-to-r from-green-600 to-green-800 hover:from-green-500 hover:to-green-700 px-6 py-3 rounded-full text-white font-semibold shadow-xl transition-all duration-300 transform hover:scale-105"
                      >
                        <span>اكتشف المزيد</span>
                        <span>→</span>
                      </button>
                    </div>
                  </div>
                </li>
              ))}
            </ul>
          </div>

          {/* النص العلوي المتحرك - يختفي عند hover */}
          <div 
            className="container relative mx-auto transition-all duration-500"
            style={{
              opacity: isAnyHovered ? 0 : 1,
              visibility: isAnyHovered ? "hidden" : "visible",
              transform: isAnyHovered ? "scale(0.95)" : "scale(1)",
              zIndex: 50
            }}
          >
            <div className="items-center flex flex-wrap">
              <div className="w-full lg:w-8/12 px-4 ml-auto mr-auto text-center">
                <div className="pr-12">
                  <h1
                    key={texts[index]}
                    className="text-white font-bold text-5xl md:text-6xl transition-all duration-500 mb-6"
                    style={{
                      textShadow: "0 0 30px rgba(34, 197, 94, 0.5), 0 0 60px rgba(34, 197, 94, 0.3)",
                      background: "linear-gradient(135deg, #ffffff 0%, #22c55e 100%)",
                      WebkitBackgroundClip: "text",
                      WebkitTextFillColor: "transparent",
                      backgroundClip: "text"
                    }}
                  >
                    {texts[index]}
                  </h1>
                  <p className="mt-4 text-xl text-gray-200 font-light">
                    مرحباً بك في نظام إدارة المطاعم الذكي
                  </p>
                  <div className="mt-6 flex justify-center gap-4">
                    <div className="w-12 h-1 bg-green-500 rounded-full"></div>
                    <div className="w-12 h-1 bg-gray-500 rounded-full"></div>
                    <div className="w-12 h-1 bg-green-500 rounded-full"></div>
                  </div>
                </div>
              </div>
            </div>
          </div>

          {/* عنصر زخرفي */}
          <div className="absolute bottom-10 left-0 right-0 z-40 flex justify-center gap-2">
            <div className="animate-pulse w-2 h-2 bg-green-500 rounded-full"></div>
            <div className="animate-pulse delay-100 w-2 h-2 bg-green-400 rounded-full"></div>
            <div className="animate-pulse delay-200 w-2 h-2 bg-green-300 rounded-full"></div>
          </div>
        </div>
      </main>
      <Footer />

      {/* مودال الصورة المكبرة */}
      {selectedImage && (
        <div
          className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-black bg-opacity-95 backdrop-blur-md transition-all duration-300"
          onClick={closeModal}
        >
          <div
            className="relative max-w-4xl w-full bg-gradient-to-br from-gray-900 to-black rounded-2xl overflow-hidden shadow-2xl transform transition-all duration-300 scale-100 border border-green-500/30"
            onClick={(e) => e.stopPropagation()}
          >
            <div className="absolute top-0 left-0 right-0 h-1 bg-gradient-to-r from-green-400 via-green-600 to-green-400"></div>

            <button
              onClick={closeModal}
              className="absolute top-4 right-4 z-10 bg-black bg-opacity-70 hover:bg-green-600 text-white w-10 h-10 rounded-full flex items-center justify-center transition-all duration-300 hover:scale-110 border border-green-500/50"
            >
              ✕
            </button>

            <div className="flex flex-col md:flex-row">
              <div className="md:w-1/2 bg-gradient-to-br from-gray-800 to-black relative overflow-hidden">
                <div className="absolute inset-0 bg-green-500/10"></div>
                <img
                  src={selectedImage.url}
                  alt={selectedImage.title}
                  className="w-full h-64 md:h-full object-cover relative z-10"
                />
              </div>
              <div className="md:w-1/2 p-8">
                <div className="flex items-center gap-3 mb-4">
                  <span className="text-4xl">{selectedImage.icon}</span>
                  <h2 className="text-3xl font-bold bg-gradient-to-r from-green-400 to-green-600 bg-clip-text text-transparent">
                    {selectedImage.title}
                  </h2>
                </div>
                <p className="text-gray-300 leading-relaxed mb-6">
                  {selectedImage.fullDescription}
                </p>
                <div className="space-y-3 mb-8">
                  {selectedImage.features.map((feature, i) => (
                    <div key={i} className="flex items-center gap-3 text-sm text-gray-200 group">
                      <span className="text-green-500 text-lg group-hover:scale-110 transition-transform">✓</span>
                      <span>{feature}</span>
                    </div>
                  ))}
                </div>
                <div className="border-t border-green-500/30 pt-4">
                  <p className="text-sm text-green-400 flex items-center gap-2">
                    <span className="animate-pulse">✨</span>
                    نظام إدارة ذكي بالكامل
                    <span className="animate-pulse">✨</span>
                  </p>
                </div>
              </div>
            </div>
          </div>
        </div>
      )}
    </>
  );
}
